        self.target = target
        self.damage = damage
        self.speed = speed
        self.color = color
        self.hit = False

    def update(self, dt):
        if not self.target or self.target.hp <= 0:
            self.hit = True
            return

        dir_x = self.target.pos.x - self.pos.x
        dir_y = self.target.pos.y - self.pos.y
        dist = math.sqrt(dir_x**2 + dir_y**2)
        if dist < 5:
