    rl.init_window(SCREEN_WIDTH, SCREEN_HEIGHT, "Neon Bastion")
    rl.set_target_fps(60)

    engine = GameEngine()

    while not rl.window_should_close():
        dt = rl.get_frame_time()
        engine.update(dt)

        rl.begin_drawing()
        engine.draw()
        rl.end_drawing()

    rl.close_window()

